from collections import defaultdict
from typing import List

class Solution:
    def maxSum(self, nums: List[int], m: int, k: int) -> int:
        n = len(nums)
        if k > n:
            return 0

        freq = defaultdict(int)
        distinct = 0
        max_sum = 0
        current_sum = 0

        # Initialize the first window
        for i in range(k):
            current_sum += nums[i]
            freq[nums[i]] += 1
            if freq[nums[i]] == 1:
                distinct += 1

        if distinct >= m:
            max_sum = current_sum

        # Slide the window
        for i in range(k, n):
            removed = nums[i - k]
            added = nums[i]

            current_sum += added - removed

            freq[removed] -= 1
            if freq[removed] == 0:
                distinct -= 1
            freq[added] += 1
            if freq[added] == 1:
                distinct += 1

            if distinct >= m:
                max_sum = max(max_sum, current_sum)

        return max_sum
